while True:
    conn, direccion = socket_servidor.accept()
    print(f"Solicitud de conexión de: {direccion}")
    
    try:
        # Mensaje de bienvenida
        mensaje_bienvenida = "!Hola, bienvenido a ViniRunner AI¡"
        conn.send(mensaje_bienvenida.encode())
        
        # Recibir y validar categoría
        categoria = conn.recv(4096).decode().strip()
        if categoria not in ["Comunidades", "Ciudades", "Atletas"]:
            conn.send("ERROR: Esa categoría no existe, amigo.".encode())
            conn.close()
            continue

        # Enviar la lista de opciones según la categoría 
        if categoria == "Atletas":
            opciones = list(Atletas.keys())
        elif categoria == "Comunidades":
            opciones = list(Comunidades.keys())
        else:
            opciones = list(Ciudades.keys())

        if categoria != "Atletas":
            conn.send(f"Elige una opción de {categoria}: {'  //  '.join(opciones)}".encode())
        else:
            conn.send(f"Elige una opción de {categoria}:".encode())
        
        # Recibir la elección y enviar la respuesta final
        seleccion = conn.recv(4096).decode().strip()

        if seleccion not in opciones:
            respuesta = f"Error: La opción de {categoria} elegida no se encuentra en la base de datos."
        else:
            if categoria == "Atletas":
                datos = Atletas[seleccion]
                respuesta = (f"El atleta {seleccion}, perteneciente al club {datos[3]}, realizó un tiempo de {datos[1]} s, con un viento de {datos[2]} m/s, el día {datos[9]}.")
            
            elif categoria == "Comunidades":
                marcas = Comunidades[seleccion][0]
                renta = Comunidades[seleccion][1]
                media = sum(marcas) / len(marcas)
                # Convertimos marcas a string para el join
                marcas_str = ", ".join([str(m) for m in marcas])
                respuesta = (f"Marcas en {seleccion}: {marcas_str}. Marca media: {media} s. Renta media: {renta} €")
            
            elif categoria == "Ciudades":
                marcas = [float(m) for m in Ciudades[seleccion][0]]
                altura = Ciudades[seleccion][1]
                media = sum(marcas) / len(marcas)
                marcas_str = ", ".join([str(m) for m in marcas])
                respuesta = (f"Marcas en {seleccion}: {marcas_str}. Marca media: {media} s. Altura: {altura }m.")

        conn.send(respuesta.encode())
    
    # Tratar excepciones
    except Exception as e:
        print(f"Error con el cliente {direccion}: {e}")
        try:
            conn.send("Error interno en el servidor".encode())
        except:
            pass
    finally:
        conn.close()